(function(){
  var questions = [{"html":"<span class=\"green-keyword\">name</span> = <span class=\"code-func\">input</span>(<span class=\"code-string\">\"Enter name\"</span>)","correct":"Stores text input","options":["Stores text input","Stores number input","Prints a message"],"right":"input() gets text from the user and stores it in name.","wrong":"input() returns text unless you convert it."},{"html":"<span class=\"green-keyword\">age</span> = <span class=\"code-func\">int</span>(<span class=\"code-func\">input</span>(<span class=\"code-string\">\"Enter age\"</span>))","correct":"Stores number input","options":["Stores text input","Stores number input","Creates a comment"],"right":"int(input(...)) converts the typed answer into a whole number.","wrong":"int() converts the input into an integer."},{"html":"<span class=\"code-string\">\"42\"</span>","correct":"String","options":["String","Integer","Float","Boolean"],"right":"Anything inside quotes is a string.","wrong":"Quotes make this a string, even though it looks like a number."},{"html":"3.14","correct":"Float","options":["String","Integer","Float","Boolean"],"right":"A decimal number is a float.","wrong":"Numbers with decimal points are floats."},{"html":"<span class=\"code-func\">float</span>(<span class=\"green-keyword\">score</span>)","correct":"Converts score to a float","options":["Converts score to a float","Converts score to a string","Asks for input"],"right":"float() converts a value to a decimal number type.","wrong":"float(variable) is the conversion for decimal numbers."}];
  var helpSlides = [{"title":"input()","body":"<p><code class=\"bg-gray-100 px-1 rounded\">input()</code> asks the user to type something and returns a string.</p>"},{"title":"Number input","body":"<p>Use <code class=\"bg-gray-100 px-1 rounded\">int(input(...))</code> for whole-number input.</p>"},{"title":"Data types","body":"<p>Strings use quotes, integers are whole numbers, floats are decimals, and booleans are <code>True</code> or <code>False</code>.</p>"}];
  var idx=0, score=0, answered=false, results=[];
  var modal=document.getElementById('selection-dna-help-modal');
  var helpTitle=document.getElementById('selection-dna-help-title');
  var helpBody=document.getElementById('selection-dna-help-body');
  var helpPager=document.getElementById('selection-dna-help-pager');
  var helpPrev=document.getElementById('selection-dna-help-prev');
  var helpNext=document.getElementById('selection-dna-help-next');
  var helpIdx=0;
  function renderSlide(){
    var slide=helpSlides[helpIdx];
    helpTitle.textContent=slide.title;
    helpBody.innerHTML=slide.body;
    helpPager.textContent=(helpIdx+1)+' / '+helpSlides.length;
    helpPrev.disabled=helpIdx===0;
    helpNext.textContent=helpIdx===helpSlides.length-1?'Close':'Next';
  }
  document.getElementById('selection-dna-help-btn').onclick=function(){ helpIdx=0; renderSlide(); modal.classList.remove('hidden'); };
  document.getElementById('selection-dna-help-close').onclick=function(){ modal.classList.add('hidden'); };
  helpPrev.onclick=function(){ if(helpIdx>0){ helpIdx--; renderSlide(); } };
  helpNext.onclick=function(){ if(helpIdx<helpSlides.length-1){ helpIdx++; renderSlide(); } else { modal.classList.add('hidden'); } };
  modal.addEventListener('click', function(e){ if(e.target===modal) modal.classList.add('hidden'); });

  var qEl=document.getElementById('selection-dna-q');
  var optEl=document.getElementById('selection-dna-opts');
  var fbEl=document.getElementById('selection-dna-fb');
  var progEl=document.getElementById('selection-dna-prog');
  var scoreEl=document.getElementById('selection-dna-score');
  function show(){
    if(idx>=questions.length){ finish(); return; }
    var q=questions[idx]; answered=false;
    progEl.textContent='Question '+(idx+1)+' of '+questions.length;
    scoreEl.textContent='Score: '+score;
    qEl.innerHTML='<span class="ex-code">'+q.html+'</span>';
    optEl.innerHTML=''; fbEl.textContent=''; fbEl.className='ex-feedback';
    q.options.forEach(function(o){
      var btn=document.createElement('button'); btn.className='ex-opt'; btn.textContent=o;
      btn.onclick=function(){
        if(answered) return; answered=true;
        optEl.querySelectorAll('.ex-opt').forEach(function(b){ b.disabled=true; if(b.textContent===q.correct) b.classList.add('correct'); });
        var correct=o===q.correct;
        results.push({q:q, wasCorrect:correct, chosen:o});
        if(correct){ btn.classList.add('correct'); score++; scoreEl.textContent='Score: '+score; fbEl.className='ex-feedback ok'; fbEl.textContent='Correct.'; setTimeout(function(){ idx++; show(); }, 900); }
        else { btn.classList.add('wrong'); fbEl.className='ex-feedback err'; fbEl.textContent='Incorrect. The answer is: '+q.correct; setTimeout(function(){ idx++; show(); }, 1800); }
      };
      optEl.appendChild(btn);
    });
  }
  function finish(){
    var pct=Math.round(score/questions.length*100);
    qEl.innerHTML=''; optEl.innerHTML=''; fbEl.textContent=''; progEl.textContent='Complete'; scoreEl.textContent='';
    var resultsEl=document.getElementById('selection-dna-results'); resultsEl.classList.remove('hidden');
    var msg=pct===100?'Full marks. You are ready to build on last lesson.':pct>=70?'Good work overall. Review anything you missed below.':'A few areas to revisit before moving on.';
    var html='<div class="ex-box"><p style="font-family:sans-serif;font-size:0.95rem;font-weight:600;color:#cdd6f4;margin-bottom:4px">'+score+'/'+questions.length+' - '+pct+'%</p><p style="font-family:sans-serif;font-size:0.85rem;color:#a6adc8;margin-bottom:16px">'+msg+'</p>';
    results.forEach(function(r){
      html+='<div style="display:flex;align-items:flex-start;gap:10px;margin-bottom:8px;padding:8px 10px;background:'+(r.wasCorrect?'#1a2f20':'#2a1a1a')+';border:1px solid '+(r.wasCorrect?'#2d4a35':'#4a2a2a')+';border-radius:6px">';
      html+='<span style="color:'+(r.wasCorrect?'#a6e3a1':'#f38ba8')+';font-size:1rem;flex-shrink:0;margin-top:1px">'+(r.wasCorrect?'&#10003;':'&#10007;')+'</span>';
      html+='<div><div class="ex-code" style="font-size:0.82rem;margin-bottom:3px">'+r.q.html+'</div>';
      html+='<p style="font-family:sans-serif;font-size:0.78rem;color:#a6adc8;margin:0 0 3px 0">Your answer: <strong style="color:'+(r.wasCorrect?'#a6e3a1':'#f38ba8')+'">'+esc(r.chosen)+'</strong> - correct: <strong style="color:#a6e3a1">'+esc(r.q.correct)+'</strong></p>';
      html+='<p style="font-family:sans-serif;font-size:0.8rem;color:#bac2de;margin:0">'+(r.wasCorrect?r.q.right:(r.q.wrong||r.q.right))+'</p></div></div>';
    });
    html+='</div>'; resultsEl.innerHTML=html;
    window.__markStepComplete && window.__markStepComplete();
  }
  function esc(str){ return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
  show();
})();

