  var idx=0, score=0;
  var prog=document.getElementById('level24-prog');
  var scoreEl=document.getElementById('level24-score');
  var qEl=document.getElementById('level24-q');
  var wrap=document.getElementById('level24-editor-wrap');
  var fb=document.getElementById('level24-fb');
  var exp=document.getElementById('level24-exp');
  function isCorrect(q, val){ return q.useRegex ? new RegExp(q.correctCode,'i').test(val.trim()) : val.trim() === q.correctCode; }
  function showHint(q){ exp.textContent=q.notice || q.explanation || ''; exp.style.display=exp.textContent ? 'block' : 'none'; }
  function render(){
    if(idx>=questions.length){ finish(); return; }
    var q=questions[idx];
    prog.textContent='Question '+(idx+1)+' of '+questions.length;
    scoreEl.textContent='Score: '+score;
    qEl.innerHTML=q.html || q.prompt || '';
    fb.textContent=''; fb.className='ex-feedback'; exp.style.display='none'; exp.textContent='';
    wrap.innerHTML='<input id="level24-answer" class="ex-input" type="text" autocomplete="off" spellcheck="false" placeholder="Type your answer here"/><button id="level24-check" class="ex-btn" style="margin-top:8px">Check</button>';
    document.getElementById('level24-check').onclick=function(){ check(q); };
    var input=document.getElementById('level24-answer'); input.onkeydown=function(e){ if(e.key==='Enter') check(q); }; input.focus();
  }
  function check(q){
    var input=document.getElementById('level24-answer'); var val=input.value.trim();
    if(!val){ fb.className='ex-feedback hint'; fb.textContent='Type your answer first.'; showHint(q); return; }
    if(isCorrect(q,val)){ score++; scoreEl.textContent='Score: '+score; input.classList.add('correct'); fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(function(){ idx++; render(); }, 900); }
    else { input.classList.add('wrong'); fb.className='ex-feedback err'; fb.textContent='Not quite. Check the syntax carefully.'; showHint(q); }
  }
  function finish(){
    prog.textContent='Complete'; qEl.innerHTML=''; wrap.innerHTML=''; exp.style.display='none';
    var pass = score >= Math.ceil(questions.length*0.7);
    fb.className='ex-feedback '+(pass?'ok':'hint');
    fb.textContent='You scored '+score+' out of '+questions.length+'. '+(pass?'Good work.':'Review the examples, then try similar questions again.');
    window.__markStepComplete && window.__markStepComplete();
  }
  render();
})();

