\s*0\\s*:$","useRegex":true,"explanation":"Format: if lives != 0:"},{"type":"extended_run","prompt":"Write a script that stores a <b>score</b> and an <b>age</b> of your choice as numbers, then writes an if statement for each:\n- Print a message if score is greater than or equal to 50\n- Print a message if age is greater than or equal to 18","explanation":"Format:\nscore = 75\nage = 20\nif score >= 50:\n    print('Passed!')\nif age >= 18:\n    print('Adult')","expectedVars":[{"name":"score","type":"number","strict":false},{"name":"age","type":"number","strict":false}],"testValues":[{"name":"score","value":75},{"name":"age","value":20}],"expectedOutput":[{"containsStr":"Passed"},{"containsStr":"Adult"}]}];
  var idx=0, score=0;
  var prog=document.getElementById('s4-prog');
  var scoreEl=document.getElementById('s4-score');
  var wrap=document.getElementById('s4-wrap');
  function rx(pattern, value){ return new RegExp(pattern,'im').test(value); }
  function render(){ if(idx>=examData.length){ finish(); return; } var q=examData[idx]; prog.textContent='Question '+(idx+1)+' of '+examData.length; scoreEl.textContent='Score: '+score; if(q.type==='mcq') renderMcq(q); else renderText(q); }
  function renderMcq(q){
